235→	r := &model.InstitutionRankings{}
236→
237→	if obj := jsonbObject(data, "us_news____national_universities"); obj != nil {
238→		r.UsNewsNational = rankValue(obj)
239→	}
240→	if obj := jsonbObject(data, "us_news____liberal_arts_colleges"); obj != nil {
241→		r.UsNewsLiberalArts = rankValue(obj)
242→	}
243→	if obj := jsonbObject(data, "forbes_____"); obj != nil {
244→		r.Forbes = rankValue(obj)
245→	}
246→	if obj := jsonbObject(data, "washington_monthly____national_universities"); obj != nil {
247→		r.WashingtonMonthlyNational = rankValue(obj)
248→	}
249→	if obj := jsonbObject(data, "washington_monthly____liberal_arts"); obj != nil {
250→		r.WashingtonMonthlyLiberalArts = rankValue(obj)
251→	}
252→	if obj := jsonbObject(data, "niche____best_colleges"); obj != nil {
253→		r.Niche = rankValue(obj)
254→	}
255→	if obj := jsonbObject(data, "money_com_____"); obj != nil {
256→		r.MoneyScore = jsonbFloat(obj, "score")
257→	}
258→
259→	if r.UsNewsNational == nil && r.UsNewsLiberalArts == nil && r.Forbes == nil &&
260→		r.WashingtonMonthlyNational == nil && r.WashingtonMonthlyLiberalArts == nil &&
261→		r.Niche == nil && r.MoneyScore == nil {
262→		return nil
263→	}
264→	return r
265→}
