267→// rankValue extracts the rank integer from a ranking object, only if method == "rank".
268→func rankValue(obj map[string]any) *int {
269→	method := jsonbString(obj, "method")
270→	if method == nil || *method != "rank" {
271→		return nil
272→	}
273→	return jsonbInt(obj, "rank")
274→}
