339→func extractCulture(data map[string]any) *model.InstitutionCulture {
340→	partisan := jsonbObject(data, "partisan_lean_538")
341→	nces := jsonbObject(data, "nces")
342→
343→	c := &model.InstitutionCulture{}
344→	if partisan != nil {
