package search

import (
	"encoding/json"
	"fmt"
	"io"
	"strconv"
	"strings"
)

// Theme categorises a search field into a UI group. Values match the
// search_base.theme PostgreSQL enum — keep them in sync.
type Theme string

const (
	ThemeCore                Theme = "CORE"
	ThemeLocation            Theme = "LOCATION"
	ThemeAcademics           Theme = "ACADEMICS"
	ThemeCost                Theme = "COST"
	ThemeOutcomes            Theme = "OUTCOMES"
	ThemeRanking             Theme = "RANKING"
	ThemeAdmissions          Theme = "ADMISSIONS"
	ThemeAthletics           Theme = "ATHLETICS"
	ThemeFieldsOfStudy       Theme = "FIELDS_OF_STUDY"
	ThemeCulturalEnvironment Theme = "CULTURAL_ENVIRONMENT"
	ThemeWeather             Theme = "WEATHER"
	ThemePhysicalEnvironment Theme = "PHYSICAL_ENVIRONMENT"
	ThemeDemographics        Theme = "DEMOGRAPHICS"
	ThemeReputation          Theme = "REPUTATION"
	ThemeSafety              Theme = "SAFETY"
	ThemeStudentLife         Theme = "STUDENT_LIFE"
	ThemeMetadata            Theme = "METADATA"
	ThemeOther               Theme = "OTHER"
)

// AllThemes is the canonical list of valid Theme values.
var AllThemes = []Theme{
	ThemeCore, ThemeLocation, ThemeAcademics, ThemeCost, ThemeOutcomes,
	ThemeRanking, ThemeAdmissions, ThemeAthletics, ThemeFieldsOfStudy,
	ThemeCulturalEnvironment, ThemeWeather, ThemePhysicalEnvironment,
	ThemeDemographics, ThemeReputation, ThemeSafety, ThemeStudentLife,
	ThemeMetadata, ThemeOther,
}

// ThemeLabel returns the human-readable UI label for a Theme.
func ThemeLabel(t Theme) string {
	switch t {
	case ThemeCore:
		return "Core"
	case ThemeLocation:
		return "Location"
	case ThemeAcademics:
		return "Academics"
	case ThemeCost:
		return "Cost & Financial Aid"
	case ThemeOutcomes:
		return "Outcomes"
	case ThemeRanking:
		return "Rankings"
	case ThemeAdmissions:
		return "Admissions"
	case ThemeAthletics:
		return "Athletics"
	case ThemeFieldsOfStudy:
		return "Fields of Study"
	case ThemeCulturalEnvironment:
		return "Cultural Environment"
	case ThemeWeather:
		return "Weather & Climate"
	case ThemePhysicalEnvironment:
		return "Physical Environment"
	case ThemeDemographics:
		return "Demographics"
	case ThemeReputation:
		return "Reputation"
	case ThemeSafety:
		return "Safety"
	case ThemeStudentLife:
		return "Student Life"
	case ThemeMetadata:
		return "Metadata"
	case ThemeOther:
		return "Other"
	default:
		return string(t)
	}
}

// MarshalGQL implements the graphql.Marshaler interface for gqlgen.
// The value must be quoted so that the JSON response is valid (matching
// the convention used by gqlgen-generated enums like FieldVisibility).
func (t Theme) MarshalGQL(w io.Writer) {
	fmt.Fprint(w, strconv.Quote(string(t))) //nolint:errcheck
}

// UnmarshalGQL implements the graphql.Unmarshaler interface for gqlgen.
func (t *Theme) UnmarshalGQL(v interface{}) error {
	s, ok := v.(string)
	if !ok {
		return fmt.Errorf("Theme must be a string")
	}
	*t = Theme(s)
	return nil
}

// EnumOption represents one selectable value in an enum facet.
type EnumOption struct {
	Value string `json:"value"`
	Label string `json:"label"`
}

// NumericBounds describes the hard min/max allowed for a numeric range field.
type NumericBounds struct {
	Min *float64 `json:"min,omitempty"`
	Max *float64 `json:"max,omitempty"`
}

// FieldVisibility controls whether a field is shown in the UI.
// Bound to the GraphQL FieldVisibility enum via gqlgen.yml.
type FieldVisibility string

const (
	VisibilityVisible    FieldVisibility = "VISIBLE"
	VisibilityRestricted FieldVisibility = "RESTRICTED"
	VisibilityHidden     FieldVisibility = "HIDDEN"
)

// MarshalGQL implements the graphql.Marshaler interface for gqlgen.
func (v FieldVisibility) MarshalGQL(w io.Writer) {
	fmt.Fprint(w, strconv.Quote(string(v))) //nolint:errcheck
}

// UnmarshalGQL implements the graphql.Unmarshaler interface for gqlgen.
func (v *FieldVisibility) UnmarshalGQL(val interface{}) error {
	s, ok := val.(string)
	if !ok {
		return fmt.Errorf("FieldVisibility must be a string")
	}
	*v = FieldVisibility(s)
	return nil
}

// FieldSearchability controls whether a field can be used as a filter.
// Bound to the GraphQL FieldSearchability enum via gqlgen.yml.
type FieldSearchability string

const (
	SearchabilitySearchable    FieldSearchability = "SEARCHABLE"
	SearchabilityRestricted    FieldSearchability = "RESTRICTED"
	SearchabilityNotSearchable FieldSearchability = "NOT_SEARCHABLE"
)

// MarshalGQL implements the graphql.Marshaler interface for gqlgen.
func (s FieldSearchability) MarshalGQL(w io.Writer) {
	fmt.Fprint(w, strconv.Quote(string(s))) //nolint:errcheck
}

// UnmarshalGQL implements the graphql.Unmarshaler interface for gqlgen.
func (s *FieldSearchability) UnmarshalGQL(val interface{}) error {
	str, ok := val.(string)
	if !ok {
		return fmt.Errorf("FieldSearchability must be a string")
	}
	*s = FieldSearchability(str)
	return nil
}

// SelectionMode controls whether a multi-enum filter requires any or all values to match.
type SelectionMode string

const (
	SelectionModeAny SelectionMode = "any"
	SelectionModeAll SelectionMode = "all"
)

// JSONBStorageFormat describes how multi-valued data is stored in the JSONB column.
type JSONBStorageFormat string

const (
	JSONBStorageFormatArray     JSONBStorageFormat = "array"
	JSONBStorageFormatObjectKey JSONBStorageFormat = "object_key"
)

// FieldDescriptor is the metadata-export contract used by the future handler.
type FieldDescriptor struct {
	Name          string             `json:"name"`
	Label         string             `json:"label"`
	Description   string             `json:"description"`
	Kind          FacetKind          `json:"kind"`
	Theme         Theme              `json:"theme"`
	Options       []EnumOption       `json:"options,omitempty"`
	Bounds        *NumericBounds     `json:"bounds,omitempty"`
	Units         string             `json:"units,omitempty"`
	SelectionMode SelectionMode      `json:"selection_mode,omitempty"`
	Visibility    FieldVisibility    `json:"visibility"`
	Searchability FieldSearchability `json:"searchability"`
	// Exportable is a pointer so that a nil value indicates the field was never
	// explicitly set, enabling the same zero-value enforcement test used for
	// Visibility and Searchability.
	Exportable *bool `json:"exportable"`
	// OutputDefault controls whether this field appears in search result columns.
	// nil = not an output field; ptr(true) = shown by default in the results
	// grid; ptr(false) = available in the column picker but hidden by default.
	OutputDefault *bool `json:"output_default,omitempty"`
	// Sortable indicates whether results can be sorted by this field.
	Sortable bool `json:"sortable,omitempty"`
	// OutputKey is the dot-separated path into the data JSONB blob for
	// extracting this field's value from search results. Empty for fields
	// that are not extractable from the data blob (e.g. tsvector, geo).
	OutputKey string `json:"output_key,omitempty"`
	// DataSourceID references the data source that provides this field's values.
	DataSourceID string `json:"data_source_id,omitempty"`
}

// Field is the core interface every search facet must implement.
type Field interface {
	Name() string
	Label() string
	Description() string
	Kind() FacetKind
	Theme() Theme
	Source() FieldSource
	Descriptor() FieldDescriptor
	// BuildSQL parses rawFilter JSON, validates, and returns a parameterised SQL
	// boolean expression. argStart is the 1-based index of the first placeholder.
	BuildSQL(rawFilter json.RawMessage, argStart int) (expr string, args []any, err error)
}

// ptr is a generic helper that returns a pointer to v.
func ptr[T any](v T) *T { return &v }

// ─────────────────────────────────────────────────────────────────────────────
// baseField — shared embedding struct
// ─────────────────────────────────────────────────────────────────────────────

type baseField struct {
	name          string
	label         string
	description   string
	kind          FacetKind
	theme         Theme
	source        FieldSource
	visibility    FieldVisibility
	searchability FieldSearchability
	exportable    *bool
	outputDefault *bool
	sortable      bool
	outputKey     string // explicit GraphQL dot-path; if empty, derived from source
	dataSourceID  string
}

func (b baseField) Name() string         { return b.name }
func (b baseField) Label() string        { return b.label }
func (b baseField) Description() string  { return b.description }
func (b baseField) Kind() FacetKind      { return b.kind }
func (b baseField) Theme() Theme         { return b.theme }
func (b baseField) Source() FieldSource  { return b.source }
func (b baseField) DataSourceID() string { return b.dataSourceID }

func (b baseField) Descriptor() FieldDescriptor {
	return FieldDescriptor{
		Name:          b.name,
		Label:         b.label,
		Description:   b.description,
		Kind:          b.kind,
		Theme:         b.theme,
		Visibility:    b.visibility,
		Searchability: b.searchability,
		Exportable:    b.exportable,
		OutputDefault: b.outputDefault,
		Sortable:      b.sortable,
		OutputKey:     b.resolvedOutputKey(),
		DataSourceID:  b.dataSourceID,
	}
}

// resolvedOutputKey returns the explicit outputKey if set, otherwise derives
// from the field source.
func (b baseField) resolvedOutputKey() string {
	if b.outputKey != "" {
		return b.outputKey
	}
	return outputKeyFromSource(b.source)
}

// outputKeyFromSource derives the output key for extracting a field's value
// from the data JSONB blob. Returns empty string for non-extractable sources.
func outputKeyFromSource(src FieldSource) string {
	switch src.Kind {
	case SourceJSONBPath:
		return strings.Join(src.JSONBPath, ".")
	case SourceColumn:
		return src.Column
	default:
		return ""
	}
}

// boolPtr is a package-level helper that returns a pointer to a bool literal.
// Use it when setting exportable in field constructors.
func boolPtr(v bool) *bool { return &v }

// jsonbNullGuard returns "ref IS NOT NULL AND " when the source is a JSONB path.
// For non-JSONB sources it returns "".
func jsonbNullGuard(src FieldSource) string {
	if src.Kind == SourceJSONBPath {
		return src.SQLRef() + " IS NOT NULL AND "
	}
	return ""
}

// ─────────────────────────────────────────────────────────────────────────────
// FullTextSearchField
// ─────────────────────────────────────────────────────────────────────────────

type FullTextSearchField struct {
	baseField
}

func (f *FullTextSearchField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter FullTextFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	col := f.source.Column
	expr := fmt.Sprintf("%s @@ plainto_tsquery('english', $%d)", col, argStart)
	return expr, []any{filter.Query}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// SubstringField
// ─────────────────────────────────────────────────────────────────────────────

type SubstringField struct {
	baseField
}

func (f *SubstringField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter SubstringFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	ref := f.source.SQLRef()
	guard := jsonbNullGuard(f.source)
	expr := fmt.Sprintf("%s%s ILIKE '%%' || $%d || '%%'", guard, ref, argStart)
	return expr, []any{filter.Value}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// ExactStringField
// ─────────────────────────────────────────────────────────────────────────────

type ExactStringField struct {
	baseField
	CaseSensitive bool
}

func (f *ExactStringField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter ExactStringFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	ref := f.source.SQLRef()
	guard := jsonbNullGuard(f.source)
	var op string
	if f.CaseSensitive {
		op = "="
	} else {
		op = "ILIKE"
	}
	expr := fmt.Sprintf("%s%s %s $%d", guard, ref, op, argStart)
	return expr, []any{filter.Value}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// ExactNumericField
// ─────────────────────────────────────────────────────────────────────────────

type ExactNumericField struct {
	baseField
	Units string
}

func (f *ExactNumericField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Units = f.Units
	return d
}

func (f *ExactNumericField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter ExactNumericFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	ref := f.source.SQLRef()
	guard := jsonbNullGuard(f.source)
	castType := sqlCastType(f.source.ValueType)
	castRef := f.source.SQLRefAs(castType)
	if f.source.Kind == SourceJSONBPath {
		expr := fmt.Sprintf("%s%s = $%d", guard, castRef, argStart)
		return expr, []any{filter.Value}, nil
	}
	expr := fmt.Sprintf("%s = $%d", ref, argStart)
	return expr, []any{filter.Value}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// NumericRangeField
// ─────────────────────────────────────────────────────────────────────────────

type NumericRangeField struct {
	baseField
	HardMin *float64
	HardMax *float64
	Units   string
}

func (f *NumericRangeField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Units = f.Units
	if f.HardMin != nil || f.HardMax != nil {
		d.Bounds = &NumericBounds{Min: f.HardMin, Max: f.HardMax}
	}
	return d
}

// hardBounds satisfies the hasHardBounds validator interface.
func (f *NumericRangeField) hardBounds() (min, max *float64) {
	return f.HardMin, f.HardMax
}

func (f *NumericRangeField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter NumericRangeFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	if filter.Min == nil && filter.Max == nil {
		return "", nil, fmt.Errorf("at least one of min or max is required")
	}

	isJSONB := f.source.Kind == SourceJSONBPath
	ref := f.source.SQLRef()
	castType := sqlCastType(f.source.ValueType)
	castRef := f.source.SQLRefAs(castType)
	guard := ""
	if isJSONB {
		guard = ref + " IS NOT NULL AND "
	}

	valueRef := ref
	if isJSONB {
		valueRef = castRef
	}

	switch {
	case filter.Min != nil && filter.Max != nil:
		expr := fmt.Sprintf("%s%s BETWEEN $%d AND $%d", guard, valueRef, argStart, argStart+1)
		return expr, []any{*filter.Min, *filter.Max}, nil
	case filter.Min != nil:
		expr := fmt.Sprintf("%s%s >= $%d", guard, valueRef, argStart)
		return expr, []any{*filter.Min}, nil
	default:
		expr := fmt.Sprintf("%s%s <= $%d", guard, valueRef, argStart)
		return expr, []any{*filter.Max}, nil
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// RankingField — embeds NumericRangeField; adds method guard on data->method='rank'
// ─────────────────────────────────────────────────────────────────────────────

type RankingField struct {
	NumericRangeField
}

func (f *RankingField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter NumericRangeFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	if filter.Min == nil && filter.Max == nil {
		return "", nil, fmt.Errorf("at least one of min or max is required")
	}

	datakey := f.source.JSONBPath[0]
	ref := f.source.SQLRef() // e.g. data #>> '{us_news____national_universities,rank}'

	methodGuard := fmt.Sprintf("(data #>> '{%s,method}') = 'rank'", datakey)
	nullGuard := fmt.Sprintf("(%s) IS NOT NULL", ref)
	castRef := fmt.Sprintf("(%s)::integer", ref)

	var rangeExpr string
	var args []any

	switch {
	case filter.Min != nil && filter.Max != nil:
		rangeExpr = fmt.Sprintf("%s BETWEEN $%d AND $%d", castRef, argStart, argStart+1)
		args = []any{*filter.Min, *filter.Max}
	case filter.Min != nil:
		rangeExpr = fmt.Sprintf("%s >= $%d", castRef, argStart)
		args = []any{*filter.Min}
	default:
		rangeExpr = fmt.Sprintf("%s <= $%d", castRef, argStart)
		args = []any{*filter.Max}
	}

	expr := strings.Join([]string{methodGuard, nullGuard, rangeExpr}, " AND ")
	return expr, args, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// GeoField
// ─────────────────────────────────────────────────────────────────────────────

type GeoField struct {
	baseField
	MaxRadiusKm float64
}

// maxRadiusKm satisfies the hasMaxRadius validator interface.
func (f *GeoField) maxRadiusKm() float64 { return f.MaxRadiusKm }

// Descriptor overrides baseField to include MaxRadiusKm in Bounds.Max so that
// callers (e.g. the searchFields GraphQL resolver) can convert it to other units
// without needing to know the concrete type.
func (f *GeoField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Bounds = &NumericBounds{Max: ptr(f.MaxRadiusKm)}
	return d
}

func (f *GeoField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter GeoFilterInput
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	col := f.source.Column
	switch filter.Kind {
	case GeoFilterKindRadius:
		if filter.Radius == nil {
			return "", nil, fmt.Errorf("radius filter requires radius object")
		}
		r := filter.Radius
		// ST_MakePoint(lng, lat); geography ST_DWithin uses metres → km*1000
		expr := fmt.Sprintf(
			"ST_DWithin(%s, ST_SetSRID(ST_MakePoint($%d, $%d), 4326), $%d * 1000)",
			col, argStart, argStart+1, argStart+2,
		)
		return expr, []any{r.Lng, r.Lat, r.RadiusKm}, nil
	case GeoFilterKindBBox:
		if filter.BBox == nil {
			return "", nil, fmt.Errorf("bbox filter requires bbox object")
		}
		b := filter.BBox
		// ST_MakeEnvelope(xmin, ymin, xmax, ymax, srid) = (minLng, minLat, maxLng, maxLat)
		expr := fmt.Sprintf(
			"ST_Intersects(%s, ST_MakeEnvelope($%d, $%d, $%d, $%d, 4326))",
			col, argStart, argStart+1, argStart+2, argStart+3,
		)
		return expr, []any{b.MinLng, b.MinLat, b.MaxLng, b.MaxLat}, nil
	default:
		return "", nil, fmt.Errorf("unknown geo filter kind: %q", filter.Kind)
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// SingleEnumField
// ─────────────────────────────────────────────────────────────────────────────

type SingleEnumField struct {
	baseField
	Options []EnumOption
}

func (f *SingleEnumField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Options = f.Options
	return d
}

// enumOptions satisfies the hasEnumOptions validator interface.
func (f *SingleEnumField) enumOptions() []EnumOption { return f.Options }

func (f *SingleEnumField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter SingleEnumFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	ref := f.source.SQLRef()
	guard := jsonbNullGuard(f.source)
	expr := fmt.Sprintf("%s%s = $%d", guard, ref, argStart)
	return expr, []any{filter.Value}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// GenderField — virtual enum backed by two JSONB boolean keys (men_only, women_only).
// Accepts "men-only", "women-only", or "coed" and translates to the appropriate
// SQL against the existing data columns without any schema changes.
// ─────────────────────────────────────────────────────────────────────────────

type GenderField struct {
	baseField
	Options []EnumOption
}

func (f *GenderField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Options = f.Options
	return d
}

// enumOptions satisfies the hasEnumOptions validator interface.
func (f *GenderField) enumOptions() []EnumOption { return f.Options }

func (f *GenderField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter SingleEnumFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}

	menRef := "data #>> '{nces,men_only}'"
	womenRef := "data #>> '{nces,women_only}'"

	switch filter.Value {
	case "men-only":
		expr := fmt.Sprintf("%s IS NOT NULL AND %s = $%d", menRef, menRef, argStart)
		return expr, []any{"1"}, nil
	case "women-only":
		expr := fmt.Sprintf("%s IS NOT NULL AND %s = $%d", womenRef, womenRef, argStart)
		return expr, []any{"1"}, nil
	case "coed":
		expr := fmt.Sprintf(
			"(%s IS NULL OR %s = $%d) AND (%s IS NULL OR %s = $%d)",
			menRef, menRef, argStart,
			womenRef, womenRef, argStart+1,
		)
		return expr, []any{"0", "0"}, nil
	default:
		return "", nil, fmt.Errorf("invalid gender value: %q", filter.Value)
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// MultiColumnEnumField — multi-select enum backed by a direct column.
// Generates: col = ANY($N::text[])
// Use this when the column holds a single scalar value and the filter should
// match rows where that value is any one of the provided choices.
// ─────────────────────────────────────────────────────────────────────────────

type MultiColumnEnumField struct {
	baseField
	Options []EnumOption
}

func (f *MultiColumnEnumField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Options = f.Options
	d.SelectionMode = SelectionModeAny
	return d
}

// enumOptions satisfies the hasEnumOptions validator interface.
func (f *MultiColumnEnumField) enumOptions() []EnumOption { return f.Options }

func (f *MultiColumnEnumField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter MultiEnumFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	if len(filter.Values) == 0 {
		return "", nil, fmt.Errorf("at least one value required")
	}
	col := f.source.Column
	expr := fmt.Sprintf("%s = ANY($%d::text[])", col, argStart)
	return expr, []any{filter.Values}, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// MultiEnumField
// ─────────────────────────────────────────────────────────────────────────────

type MultiEnumField struct {
	baseField
	Options       []EnumOption
	SelectionMode SelectionMode
	StorageFormat JSONBStorageFormat
}

func (f *MultiEnumField) Descriptor() FieldDescriptor {
	d := f.baseField.Descriptor()
	d.Options = f.Options
	d.SelectionMode = f.SelectionMode
	return d
}

// enumOptions satisfies the hasEnumOptions validator interface.
func (f *MultiEnumField) enumOptions() []EnumOption { return f.Options }

func (f *MultiEnumField) BuildSQL(rawFilter json.RawMessage, argStart int) (string, []any, error) {
	var filter MultiEnumFilter
	if err := json.Unmarshal(rawFilter, &filter); err != nil {
		return "", nil, err
	}
	if len(filter.Values) == 0 {
		return "", nil, fmt.Errorf("at least one value required")
	}

	// Use data -> 'key' for containment / existence operators (JSONB, not text).
	// Only single-level paths are supported for MultiEnum.
	topKey := f.source.JSONBPath[0]
	jsonbRef := fmt.Sprintf("data -> '%s'", topKey)

	var expr string
	var args []any

	switch {
	case f.StorageFormat == JSONBStorageFormatArray && f.SelectionMode == SelectionModeAny:
		expr = fmt.Sprintf("%s ?| $%d::text[]", jsonbRef, argStart)
		args = []any{filter.Values}
	case f.StorageFormat == JSONBStorageFormatArray && f.SelectionMode == SelectionModeAll:
		jsonArr, err := json.Marshal(filter.Values)
		if err != nil {
			return "", nil, err
		}
		expr = fmt.Sprintf("%s @> $%d::jsonb", jsonbRef, argStart)
		args = []any{string(jsonArr)}
	case f.StorageFormat == JSONBStorageFormatObjectKey && f.SelectionMode == SelectionModeAny:
		expr = fmt.Sprintf("%s ?| $%d::text[]", jsonbRef, argStart)
		args = []any{filter.Values}
	case f.StorageFormat == JSONBStorageFormatObjectKey && f.SelectionMode == SelectionModeAll:
		expr = fmt.Sprintf("%s ?& $%d::text[]", jsonbRef, argStart)
		args = []any{filter.Values}
	default:
		return "", nil, fmt.Errorf("unsupported MultiEnum storage/selection combination: %s/%s",
			f.StorageFormat, f.SelectionMode)
	}
	return expr, args, nil
}

