package handler

import (
	"encoding/csv"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"strconv"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/kapow/api/internal/search"
)

// ExportCSV returns an HTTP handler that streams search results as a CSV file.
// It reads filter, sort, and user-location parameters from the query string,
// builds a search query capped at maxRows, and writes the results as CSV.
func ExportCSV(pool *pgxpool.Pool, reg *search.Registry, maxRows int) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		q := r.URL.Query()

		// Parse filters from query param.
		var filters []search.FilterInput
		if filtersParam := q.Get("filters"); filtersParam != "" {
			if err := json.Unmarshal([]byte(filtersParam), &filters); err != nil {
				writeJSONError(w, http.StatusBadRequest,
					fmt.Sprintf("handler: invalid filters JSON: %v", err))
				return
			}
		}

		req := search.SearchRequest{
			Filters: filters,
			Limit:   maxRows, // request the maximum; BuildExportQuery caps it
		}

		// Parse sort.
		if sortParam := q.Get("sort"); sortParam != "" {
			req.Sort = &search.SortInput{
				Field:     sortParam,
				Direction: search.SortDirectionAsc,
			}
			if dirParam := q.Get("sortDir"); dirParam == "DESC" {
				req.Sort.Direction = search.SortDirectionDesc
			}
		}

		// Parse user location.
		latStr, lngStr := q.Get("userLat"), q.Get("userLng")
		if latStr != "" && lngStr != "" {
			lat, errLat := strconv.ParseFloat(latStr, 64)
			lng, errLng := strconv.ParseFloat(lngStr, 64)
			if errLat != nil || errLng != nil {
				writeJSONError(w, http.StatusBadRequest, "handler: invalid userLat/userLng")
				return
			}
			req.UserLocation = &search.UserLocation{
				Latitude:  lat,
				Longitude: lng,
			}
			if stateParam := q.Get("userState"); stateParam != "" {
				req.UserLocation.State = stateParam
			}
		}

		// Validate the request. Export has no auth; treat as authenticated to
		// allow all fields (access control is handled at the HTTP layer).
		if errs := search.ValidateRequest(reg, req, true); len(errs) > 0 {
			body, _ := json.Marshal(map[string]any{"errors": errs})
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			_, _ = w.Write(body)
			return
		}

		// Build and execute the export query.
		sqlStr, args, err := search.BuildExportQuery(reg, req, maxRows)
		if err != nil {
			slog.ErrorContext(r.Context(), "handler: build export query", "error", err)
			writeJSONError(w, http.StatusInternalServerError, "handler: failed to build query")
			return
		}

		rows, err := pool.Query(r.Context(), sqlStr, args...)
		if err != nil {
			slog.ErrorContext(r.Context(), "handler: export query", "error", err)
			writeJSONError(w, http.StatusInternalServerError, "handler: query failed")
			return
		}
		defer rows.Close()

		// Get exportable field descriptors for CSV columns.
		descriptors := reg.ExportableDescriptors()

		// Build CSV header row from descriptor labels.
		header := make([]string, len(descriptors))
		for i, d := range descriptors {
			header[i] = d.Label
		}

		// Scan all rows before writing — allows error handling before
		// committing to 200 + CSV headers.
		type rowData struct {
			unitID          string
			institutionName string
			city            string
			state           string
			data            json.RawMessage
		}
		var rowResults []rowData

		for rows.Next() {
			var (
				unitID, instName, city, state string
				lat, lng, distance            *float64
				myPrice                       *int
				data                          json.RawMessage
				blendScore                    *float64 // column 10: unused in export but must be scanned
			)
			if err := rows.Scan(&unitID, &instName, &city, &state,
				&lat, &lng, &distance, &myPrice, &data, &blendScore); err != nil {
				slog.ErrorContext(r.Context(), "handler: scan export row", "error", err)
				writeJSONError(w, http.StatusInternalServerError, "handler: scan failed")
				return
			}
			rowResults = append(rowResults, rowData{
				unitID:          unitID,
				institutionName: instName,
				city:            city,
				state:           state,
				data:            data,
			})
		}
		if err := rows.Err(); err != nil {
			slog.ErrorContext(r.Context(), "handler: export rows iteration", "error", err)
			writeJSONError(w, http.StatusInternalServerError, "handler: query iteration failed")
			return
		}

		// Write CSV response.
		w.Header().Set("Content-Type", "text/csv; charset=utf-8")
		w.Header().Set("Content-Disposition", `attachment; filename="colleges-export.csv"`)

		cw := csv.NewWriter(w)
		if err := cw.Write(header); err != nil {
			slog.ErrorContext(r.Context(), "handler: write CSV header", "error", err)
			return
		}

		record := make([]string, len(descriptors))
		for _, row := range rowResults {
			for i, d := range descriptors {
				record[i] = extractCoreOrJSONB(d, row.unitID, row.institutionName, row.city, row.state, row.data)
			}
			if err := cw.Write(record); err != nil {
				slog.ErrorContext(r.Context(), "handler: write CSV row", "error", err)
				return
			}
		}
		// Append data sources citation section.
		writeCitationSection(cw, descriptors)

		cw.Flush()
		if err := cw.Error(); err != nil {
			slog.ErrorContext(r.Context(), "handler: flush CSV", "error", err)
		}
	}
}

// writeCitationSection appends a "Data Sources" section to the CSV listing each
// unique data source referenced by the exported fields.
func writeCitationSection(cw *csv.Writer, descriptors []search.FieldDescriptor) {
	// Build ID→DataSource lookup.
	allSources := search.AllDataSources()
	sourceByID := make(map[string]search.DataSource, len(allSources))
	for _, ds := range allSources {
		sourceByID[ds.ID] = ds
	}

	// Collect unique sources in stable order (first-seen among descriptors).
	seen := make(map[string]bool)
	var sources []search.DataSource
	for _, d := range descriptors {
		if d.DataSourceID == "" || seen[d.DataSourceID] {
			continue
		}
		seen[d.DataSourceID] = true
		if ds, ok := sourceByID[d.DataSourceID]; ok {
			sources = append(sources, ds)
		}
	}
	if len(sources) == 0 {
		return
	}

	_ = cw.Write([]string{}) // blank separator row
	_ = cw.Write([]string{"Data Sources"})
	_ = cw.Write([]string{"Source", "Dataset", "URL"})
	for _, ds := range sources {
		_ = cw.Write([]string{ds.Name, ds.Dataset, ds.URL})
	}
}

// extractCoreOrJSONB returns the CSV cell value for a descriptor.
// Core fields (name, city, state, unit_id) are extracted from scanned columns;
// all others are extracted from the data JSONB blob via OutputKey.
func extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
	switch d.Name {
	case "name":
		return instName
	case "city":
		return city
	case "state":
		return state
	case "unit_id":
		return unitID
	default:
		if d.OutputKey == "" {
			return ""
		}
		return extractJSONBValue(data, d.OutputKey)
	}
}

// extractJSONBValue navigates a dot-separated path into a JSON blob and
// returns the value as a string. Returns "" for nil, missing, or unparseable.
func extractJSONBValue(data json.RawMessage, dotPath string) string {
	if len(data) == 0 {
		return ""
	}
	parts := strings.Split(dotPath, ".")
	var current any
	if err := json.Unmarshal(data, &current); err != nil {
		return ""
	}
	for _, part := range parts {
		m, ok := current.(map[string]any)
		if !ok {
			return ""
		}
		current, ok = m[part]
		if !ok {
			return ""
		}
	}
	if current == nil {
		return ""
	}
	return fmt.Sprintf("%v", current)
}

// writeJSONError writes a JSON error response with the given status code and message.
func writeJSONError(w http.ResponseWriter, status int, message string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
}

