package search

import (
	"encoding/json"
	"strings"
	"testing"
)

func TestMultiEnumField_ArrayAll(t *testing.T) {
	t.Parallel()
	f := &MultiEnumField{
		baseField: baseField{
			name:   "test_array_all",
			source: FieldSource{Kind: SourceJSONBPath, JSONBPath: []string{"test_key"}, ValueType: JSONBArray},
		},
		SelectionMode: SelectionModeAll,
		StorageFormat: JSONBStorageFormatArray,
	}
	raw, _ := json.Marshal(MultiEnumFilter{Values: []string{"a", "b"}})
	expr, _, err := f.BuildSQL(raw, 1)
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(expr, "@>") {
		t.Errorf("expected @> operator: %s", expr)
	}
	if !strings.Contains(expr, "::jsonb") {
		t.Errorf("expected ::jsonb cast: %s", expr)
	}
}

func TestMultiEnumField_ObjectKeyAll(t *testing.T) {
	t.Parallel()
	f := &MultiEnumField{
		baseField: baseField{
			name:   "test_objkey_all",
			source: FieldSource{Kind: SourceJSONBPath, JSONBPath: []string{"test_key"}, ValueType: JSONBObject},
		},
		SelectionMode: SelectionModeAll,
		StorageFormat: JSONBStorageFormatObjectKey,
	}
	raw, _ := json.Marshal(MultiEnumFilter{Values: []string{"a", "b"}})
	expr, _, err := f.BuildSQL(raw, 1)
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(expr, "?&") {
		t.Errorf("expected ?& operator: %s", expr)
	}
}

func TestMultiEnumField_UnsupportedCombination(t *testing.T) {
	t.Parallel()
	f := &MultiEnumField{
		baseField: baseField{
			name:   "test_unsupported",
			source: FieldSource{Kind: SourceJSONBPath, JSONBPath: []string{"test_key"}},
		},
		SelectionMode: "unknown_mode",
		StorageFormat: "unknown_format",
	}
	raw, _ := json.Marshal(MultiEnumFilter{Values: []string{"a"}})
	_, _, err := f.BuildSQL(raw, 1)
	if err == nil {
		t.Error("expected error for unsupported combination")
	}
	if !strings.Contains(err.Error(), "unsupported MultiEnum") {
		t.Errorf("unexpected error: %v", err)
	}
}

func TestSqlCastType_AllBranches(t *testing.T) {
	t.Parallel()
	cases := []struct {
		vt   JSONBValueType
		want string
	}{
		{JSONBInteger, "integer"},
		{JSONBNumeric, "numeric"},
		{JSONBBoolean, "boolean"},
		{JSONBText, "text"},
		{JSONBArray, "text"},   // default
		{JSONBObject, "text"},  // default
	}
	for _, tc := range cases {
		got := sqlCastType(tc.vt)
		if got != tc.want {
			t.Errorf("sqlCastType(%s) = %q, want %q", tc.vt, got, tc.want)
		}
	}
}

func TestMultiColumnEnumField_EnumOptions(t *testing.T) {
	t.Parallel()
	opts := []EnumOption{{Value: "a", Label: "A"}, {Value: "b", Label: "B"}}
	f := &MultiColumnEnumField{
		baseField: baseField{name: "test_mce"},
		Options:   opts,
	}
	got := f.enumOptions()
	if len(got) != 2 {
		t.Errorf("expected 2 options, got %d", len(got))
	}
}

func TestAllFields_HaveValidTheme(t *testing.T) {
	t.Parallel()
	valid := make(map[Theme]bool, len(AllThemes))
	for _, th := range AllThemes {
		valid[th] = true
	}
	for _, f := range allFields() {
		theme := f.Theme()
		if theme == "" {
			t.Errorf("field %q has empty theme", f.Name())
		} else if !valid[theme] {
			t.Errorf("field %q has unknown theme %q", f.Name(), theme)
		}
	}
}

func TestThemeLabel_AllThemes(t *testing.T) {
	t.Parallel()
	for _, th := range AllThemes {
		label := ThemeLabel(th)
		if label == "" {
			t.Errorf("ThemeLabel(%q) returned empty string", th)
		}
		if label == string(th) {
			t.Errorf("ThemeLabel(%q) returned raw constant value; expected human label", th)
		}
	}
}

func TestTheme_DescriptorIncludesTheme(t *testing.T) {
	t.Parallel()
	f := &FullTextSearchField{baseField: baseField{
		name:          "test",
		theme:         ThemeCore,
		kind:          KindFullText,
		source:        FieldSource{Kind: SourceTSVector, Column: "tsv"},
		visibility:    VisibilityVisible,
		searchability: SearchabilitySearchable,
		exportable:    boolPtr(true),
	}}
	d := f.Descriptor()
	if d.Theme != ThemeCore {
		t.Errorf("Descriptor().Theme = %q, want %q", d.Theme, ThemeCore)
	}
}

func TestAllFields_DataSourceIDRequired(t *testing.T) {
	t.Parallel()
	for _, f := range allFields() {
		d := f.Descriptor()
		if d.DataSourceID == "" {
			t.Errorf("field %q: DataSourceID is empty (must be set explicitly)", d.Name)
		}
	}
}

func TestAllFields_DataSourceIDValid(t *testing.T) {
	t.Parallel()
	valid := make(map[string]bool, len(AllDataSources()))
	for _, s := range AllDataSources() {
		valid[s.ID] = true
	}
	for _, f := range allFields() {
		d := f.Descriptor()
		if d.DataSourceID != "" && !valid[d.DataSourceID] {
			t.Errorf("field %q: DataSourceID %q is not in AllDataSources()", d.Name, d.DataSourceID)
		}
	}
}

func TestTheme_GQLMarshalUnmarshal(t *testing.T) {
	t.Parallel()
	th := ThemeAcademics
	var buf strings.Builder
	th.MarshalGQL(&buf)
	if buf.String() != `"ACADEMICS"` {
		t.Errorf("MarshalGQL wrote %q, want %q", buf.String(), `"ACADEMICS"`)
	}

	var parsed Theme
	if err := parsed.UnmarshalGQL("LOCATION"); err != nil {
		t.Fatal(err)
	}
	if parsed != ThemeLocation {
		t.Errorf("UnmarshalGQL result = %q, want %q", parsed, ThemeLocation)
	}

	if err := parsed.UnmarshalGQL(123); err == nil {
		t.Error("expected error for non-string UnmarshalGQL input")
	}
}

package handler_test

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"net/url"
	"testing"

	"github.com/ketang/kapow/api/internal/handler"
	"github.com/ketang/kapow/api/internal/search"
)

// ─────────────────────────────────────────────────────────────────────────────
// ExportCSV — unit tests (no real DB)
// ─────────────────────────────────────────────────────────────────────────────

func TestExportCSV_InvalidFiltersJSON(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?filters=" + url.QueryEscape("not valid json")
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body map[string]string
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if body["error"] == "" {
		t.Error("expected non-empty error message")
	}
}

func TestExportCSV_InvalidFilterField(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"does_not_exist","value":{"value":"x"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body struct {
		Errors []struct {
			Field   string `json:"field"`
			Message string `json:"message"`
		} `json:"errors"`
	}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if len(body.Errors) == 0 {
		t.Error("expected at least 1 validation error")
	}
}

func TestExportCSV_InvalidUserLatLng(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?userLat=abc&userLng=def"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

func TestExportCSV_SortDistanceWithoutLocation(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?sort=DISTANCE"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	// ValidateRequest should catch sort=DISTANCE without userLocation.
	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

